#include <bits/stdc++.h>using namespace std; // macros#define ll long long#define yes cout << "YES\n"#define no cout << "NO\n"#define f(i, size) for (int i = 0; i < size; i++)// #define ia(a, n) \//     int a[n];     \//     f(i, n) cin >> a[i] #define iv(v, n)     \    vector<ll> v(n); \    f(i, n) cin >> v[i] // #define M (1000000007)#define INF 1000000000000000000LL#define mp make_pair#define mt make_tuple #define nline '\n'#define pb push_back#define pii pair<int, int>#define pll pair<ll, ll>#define vii vector<pair<int, int>> void solve() {    ll x,y;    cin>>x>>y;    ll n=x+y;    ll mxo=n;    if(!n&1) mxo=n-1;    ll mxe=n/2;    if(x>mxe || y>mxo) {        no;        return;    }    if(n%2==0) x--;    if(x<0){ no; return; }    yes;     for(int i=2; i<=(n-x); i++){        //pahe odd ko connect krdo        cout<<1<<" "<<i<<nline;    }    ll k=2;    for(int i=(n-x+1); i<=n; i++){        // connect a leaf and make the nodes even        cout<<k<<" "<<i<<nline;        k++;    } }  int main(){    ios::sync_with_stdio(false);    cin.tie(nullptr);    cout.tie(nullptr);     ll t;    cin >> t;    while (t--) {        solve();    }    return 0;}